import { 
  Networks, 
  TransactionBuilder,
  BASE_FEE
} from '@stellar/stellar-sdk'
import { 
  isConnected, 
  getPublicKey, 
  signTransaction
} from '@stellar/freighter-api'

const NETWORK_PASSPHRASE = Networks.TESTNET
const RPC_URL = 'https://soroban-testnet.stellar.org:443'

const CONTRACT_ID = 'YOUR_CONTRACT_ID_HERE'

let walletAddress = null

export async function initWallet() {
  const connected = await isConnected()
  if (connected) {
    walletAddress = await getPublicKey()
  }
  return walletAddress
}

export async function getWalletAddress() {
  if (!walletAddress) {
    walletAddress = await getPublicKey()
  }
  return walletAddress
}

// Mock function to simulate calling the contract
export async function callContract(method, args = {}) {
  const address = await getWalletAddress()

  const funcMap = {
    mint_nft: 'mint_nft',
    transfer_shares: 'transfer_shares',
    burn_nft: 'burn_nft',
    view_nft: 'view_nft',
    view_shares: 'view_shares',
    view_platform_stats: 'view_platform_stats'
  }

  return {
    method: funcMap[method] || method,
    args,
    address
  }
}

// Mock functions to simulate contract calls for demo purposes
export async function simulateMintNFT(creatorId, title, descrip, totalShares) {
  const address = await getWalletAddress()
  return {
    method: 'mint_nft',
    creator_id: creatorId,
    title,
    descrip,
    total_shares: totalShares,
    source: address
  }
}

export async function simulateTransferShares(nftId, fromId, toId, amount) {
  const address = await getWalletAddress()
  return {
    method: 'transfer_shares',
    nft_id: nftId,
    from_id: fromId,
    to_id: toId,
    amount,
    source: address
  }
}

export async function simulateBurnNFT(nftId, burnerId) {
  const address = await getWalletAddress()
  return {
    method: 'burn_nft',
    nft_id: nftId,
    burner_id: burnerId,
    source: address
  }
}

// Data parsing functions
export function parseNFTData(result) {
  if (!result) return null

  try {
    if (result.nft_id && result.nft_id !== 0) {
      return {
        nftId: Number(result.nft_id),
        title: result.title || 'Unknown',
        descrip: result.descrip || '',
        totalShares: Number(result.total_shares),
        ownerShares: Number(result.owner_shares),
        isActive: result.is_active,
        createdAt: Number(result.created_at)
      }
    }
  } catch (e) {
    console.error('Error parsing NFT data:', e)
  }
  return null
}

export function parseShareHolderData(result) {
  if (!result) return null
  return {
    nftId: Number(result.nft_id),
    holderId: Number(result.holder_id),
    shares: Number(result.shares)
  }
}

export function parsePlatformStats(result) {
  if (!result) return { totalNfts: 0, totalTransfers: 0, activeNfts: 0 }
  return {
    totalNfts: Number(result.total_nfts),
    totalTransfers: Number(result.total_transfers),
    activeNfts: Number(result.active_nfts)
  }
}

export function getContractId() {
  return CONTRACT_ID
}

export function getNetwork() {
  return NETWORK_PASSPHRASE
}
